const PRICE = {
  input:       1.1   / 1_000_000,
  inputCached: 0.275 / 1_000_000,
  output:      4.4   / 1_000_000,
};

function pickUsage(obj = {}) {
  const v1 = obj.kwargs?.response_metadata?.usage;
  if (v1) {
    return {
      prompt:       v1.prompt_tokens ?? 0,
      completion:   v1.completion_tokens ?? 0,
      cached:       v1.prompt_tokens_details?.cached_tokens ?? 0,
    };
  }

  const v2 = obj.usage_metadata;
  if (v2) {
    return {
      prompt:       v2.input_tokens ?? 0,
      completion:   v2.output_tokens ?? 0,
      cached:       v2.input_token_details?.cache_read ?? 0,
    };
  }

  return { prompt: 0, completion: 0, cached: 0 };
}

// 🔥 FUNÇÃO RECURSIVA
function processSteps(steps = []) {
  let promptT = 0;
  let completionT = 0;
  let cachedT = 0;

  for (const step of steps) {
    if (!step.action) continue;

    // 🔹 1. pega tokens do próprio step
    const msg = step.action.messageLog?.[0];
    if (msg) {
      const u = pickUsage(msg);
      promptT     += u.prompt;
      completionT += u.completion;
      cachedT     += u.cached;
    }

    // 🔹 2. tenta parsear observation (subagente)
    if (step.observation) {
      try {
        let obs = step.observation;

        // se for string, tenta converter
        if (typeof obs === 'string') {
          obs = JSON.parse(obs);
        }

        // se vier no formato [{ output, intermediateSteps }]
        if (Array.isArray(obs)) {
          for (const item of obs) {
            if (item.intermediateSteps) {
              const sub = processSteps(item.intermediateSteps);

              promptT     += sub.promptT;
              completionT += sub.completionT;
              cachedT     += sub.cachedT;
            }
          }
        }

      } catch (e) {
        // ignora erro de parse
      }
    }
  }

  return { promptT, completionT, cachedT };
}

// 🔥 MAIN
let totalPrompt = 0;
let totalCompletion = 0;
let totalCached = 0;

const executionDataRaw = $json.body?.executionData;

// pega direto os steps corretos
const rootSteps = executionDataRaw?.intermediateSteps ?? [];

const result = processSteps(rootSteps);

totalPrompt     += result.promptT;
totalCompletion += result.completionT;
totalCached     += result.cachedT;

// 🔥 custo final
const nonCached = totalPrompt - totalCached;

const totalCost =
  (nonCached * PRICE.input) +
  (totalCached * PRICE.inputCached) +
  (totalCompletion * PRICE.output);

return [{
  json: {
    totalCostUSD: +totalCost.toFixed(6),
    totalTokens: totalPrompt + totalCompletion,
    promptTokens: totalPrompt,
    completionTokens: totalCompletion,
    cachedTokens: totalCached
  }
}];
